import React, { useState } from 'react';

const App = () => {
  const [models, setModels] = useState([{
    id: 1,
    name: 'Model 1',
    description: 'Model 1 Description',
    performance: 'Model 1 Performance'
  }, {
    id: 2,
    name: 'Model 2',
    description: 'Model 2 Description',
    performance: 'Model 2 Performance'
  }, {
    id: 3,
    name: 'Model 3',
    description: 'Model 3 Description',
    performance: 'Model 3 Performance'
  }]);
  const [filter, setFilter] = useState(null);
  const [sort, setSort] = useState(null);
  const [search, setSearch] = useState('');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="max-w-md mx-auto p-4 bg-[#B7D7CD] shadow-md">
        <h1 className="text-3xl font-bold mb-4">AI Model Comparison Dashboard</h1>

        <div className="mb-4">
          <input
            type="search"
            className="block w-full p-2 pl-10 text-sm text-gray-700 bg-gray-50 rounded-md"
            placeholder="Search..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <button
          className="bg-[#C06C88] hover:bg-[#411C56] text-white font-bold py-2 px-4 rounded-md"
          onClick={() => setFilter('performance')}
        >Filter by Performance</button>

        <button
          className="bg-[#C06C88] hover:bg-[#411C56] text-white font-bold py-2 px-4 rounded-md"
          onClick={() => setSort('name')}
        >Sort by Name</button>

        <button
          className="bg-[#C06C88] hover:bg-[#411C56] text-white font-bold py-2 px-4 rounded-md"
          onClick={() => setSort('performance')}
        >Sort by Performance</button>

        <div className="overflow-hidden rounded-md shadow-md">
          {models.map((model) => (
            <div key={model.id} className="bg-[#B7D7CD] p-4 m-2 rounded-md">
              <h2 className="text-2xl font-bold mb-2">{model.name}</h2>
              <p className="text-gray-700 mb-4">{model.description}</p>
              <p className="text-gray-700">{model.performance}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;
